"use strict";(self.webpackChunkknowledge_base=self.webpackChunkknowledge_base||[]).push([["266"],{6164(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/Marketing","label":"BandMath: Comprehensive Feature Documentation","docId":"Marketing","unlisted":false},{"type":"category","label":"Getting Started","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Getting_Started/Creating_a_Band","label":"Creating a Band","docId":"Getting_Started/Creating_a_Band","unlisted":false},{"type":"link","href":"/docs/Getting_Started/Inviting_the_Band","label":"Inviting the Band","docId":"Getting_Started/Inviting_the_Band","unlisted":false},{"type":"link","href":"/docs/Getting_Started/The_First_Tour","label":"The First Tour: A Quick Walkthrough","docId":"Getting_Started/The_First_Tour","unlisted":false}]},{"type":"category","label":"Features","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Custodial Accounting","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/custodial-accounting/automated-debt-settlement","label":"Automated Debt Settlement","docId":"Features/custodial-accounting/automated-debt-settlement","unlisted":false},{"type":"link","href":"/docs/Features/custodial-accounting/shared-expenses-credits","label":"Shared Expenses & Credits","docId":"Features/custodial-accounting/shared-expenses-credits","unlisted":false}]},{"type":"category","label":"Core Financial Ledger","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/core-financial-ledger/add-modify-and-delete-transactions","label":"Add, Modify, and Delete Transactions","docId":"Features/core-financial-ledger/add-modify-and-delete-transactions","unlisted":false},{"type":"link","href":"/docs/Features/core-financial-ledger/advanced-profit-splitting-the-penny-catcher","label":"Advanced Profit Splitting (\\"The Penny Catcher\\")","docId":"Features/core-financial-ledger/advanced-profit-splitting-the-penny-catcher","unlisted":false},{"type":"link","href":"/docs/Features/core-financial-ledger/member-balances-settlements","label":"Member Balances & Settlements","docId":"Features/core-financial-ledger/member-balances-settlements","unlisted":false},{"type":"link","href":"/docs/Features/core-financial-ledger/smart-receipt-capture","label":"Smart Receipt Capture","docId":"Features/core-financial-ledger/smart-receipt-capture","unlisted":false}]},{"type":"category","label":"Advanced Tour Accounting","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/advanced-tour-accounting/the-venue-split-calculator","label":"The Venue Split Calculator","docId":"Features/advanced-tour-accounting/the-venue-split-calculator","unlisted":false},{"type":"link","href":"/docs/Features/advanced-tour-accounting/vat-bank-integration","label":"VAT Bank Integration","docId":"Features/advanced-tour-accounting/vat-bank-integration","unlisted":false}]},{"type":"category","label":"The Point-of-Sale (POS) System","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/the-point-of-sale-pos-system/cash-card-tracking","label":"Cash & Card Tracking","docId":"Features/the-point-of-sale-pos-system/cash-card-tracking","unlisted":false},{"type":"link","href":"/docs/Features/the-point-of-sale-pos-system/customer-email-capture","label":"Customer Email Capture","docId":"Features/the-point-of-sale-pos-system/customer-email-capture","unlisted":false},{"type":"link","href":"/docs/Features/the-point-of-sale-pos-system/discounts-tips","label":"Discounts & Tips","docId":"Features/the-point-of-sale-pos-system/discounts-tips","unlisted":false},{"type":"link","href":"/docs/Features/the-point-of-sale-pos-system/dynamic-cart-system","label":"Dynamic Cart System","docId":"Features/the-point-of-sale-pos-system/dynamic-cart-system","unlisted":false}]},{"type":"category","label":"Merch Inventory Management","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/merch-inventory-management/historical-cost-tracking","label":"Historical Cost Tracking","docId":"Features/merch-inventory-management/historical-cost-tracking","unlisted":false},{"type":"link","href":"/docs/Features/merch-inventory-management/product-size-management","label":"Product & Size Management","docId":"Features/merch-inventory-management/product-size-management","unlisted":false},{"type":"link","href":"/docs/Features/merch-inventory-management/real-time-stock-depletion","label":"Real-time Stock Depletion","docId":"Features/merch-inventory-management/real-time-stock-depletion","unlisted":false}]},{"type":"category","label":"The Merch Analyzer","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/the-merch-analyzer/profit-roi-tracking","label":"Profit & ROI Tracking","docId":"Features/the-merch-analyzer/profit-roi-tracking","unlisted":false},{"type":"link","href":"/docs/Features/the-merch-analyzer/restock-warnings","label":"Restock Warnings","docId":"Features/the-merch-analyzer/restock-warnings","unlisted":false},{"type":"link","href":"/docs/Features/the-merch-analyzer/trophy-awards-top-performers","label":"\\"Trophy\\" Awards (Top Performers)","docId":"Features/the-merch-analyzer/trophy-awards-top-performers","unlisted":false}]},{"type":"category","label":"Export & Portability","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/export-portability/email-contact-list-export","label":"Email Contact List Export","docId":"Features/export-portability/email-contact-list-export","unlisted":false},{"type":"link","href":"/docs/Features/export-portability/ledger-export-to-csv","label":"Ledger Export to CSV","docId":"Features/export-portability/ledger-export-to-csv","unlisted":false}]}]},{"type":"category","label":"Team Management","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Team_Management/Admins_vs_Members","label":"Admins vs. Members","docId":"Team_Management/Admins_vs_Members","unlisted":false},{"type":"link","href":"/docs/Team_Management/Shadow_Profiles","label":"Shadow Profiles","docId":"Team_Management/Shadow_Profiles","unlisted":false},{"type":"link","href":"/docs/Team_Management/Claiming_a_Profile","label":"Claiming a Profile","docId":"Team_Management/Claiming_a_Profile","unlisted":false}]},{"type":"category","label":"Billing & Account","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Billing_and_Account/Upgrading_and_Downgrading","label":"Upgrading and Downgrading","docId":"Billing_and_Account/Upgrading_and_Downgrading","unlisted":false},{"type":"link","href":"/docs/Billing_and_Account/Managing_Payment_Methods","label":"Managing Payment Methods","docId":"Billing_and_Account/Managing_Payment_Methods","unlisted":false},{"type":"link","href":"/docs/Billing_and_Account/Cancellations_and_Data_Export","label":"Cancellations and Data Export","docId":"Billing_and_Account/Cancellations_and_Data_Export","unlisted":false}]},{"type":"category","label":"Settings & Preferences","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Settings_and_Preferences/Localization","label":"Localization and Currency","docId":"Settings_and_Preferences/Localization","unlisted":false},{"type":"link","href":"/docs/Settings_and_Preferences/Notifications","label":"Notifications","docId":"Settings_and_Preferences/Notifications","unlisted":false}]},{"type":"category","label":"Troubleshooting","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Troubleshooting/Retroactive_VAT","label":"The Retroactive VAT Correction","docId":"Troubleshooting/Retroactive_VAT","unlisted":false},{"type":"link","href":"/docs/Troubleshooting/At_Cost_Member_Purchase","label":"The \\"At-Cost\\" Member Purchase","docId":"Troubleshooting/At_Cost_Member_Purchase","unlisted":false},{"type":"link","href":"/docs/Troubleshooting/Incorrect_Merch_Transaction","label":"The Incorrect Merch Transaction","docId":"Troubleshooting/Incorrect_Merch_Transaction","unlisted":false}]},{"type":"category","label":"Glossary","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Glossary/Glossary_of_Terms","label":"Glossary of Terms","docId":"Glossary/Glossary_of_Terms","unlisted":false}]}]},"docs":{"Billing_and_Account/Cancellations_and_Data_Export":{"id":"Billing_and_Account/Cancellations_and_Data_Export","title":"Cancellations and Data Export","description":"If the band breaks up (we hope not!) or you simply no longer need to use BandMath, you can cancel your subscription and export your data at any time.","sidebar":"tutorialSidebar"},"Billing_and_Account/Managing_Payment_Methods":{"id":"Billing_and_Account/Managing_Payment_Methods","title":"Managing Payment Methods","description":"BandMath partners with Stripe to securely handle all billing and subscription data. This ensures that your credit card information is never stored directly on BandMath servers.","sidebar":"tutorialSidebar"},"Billing_and_Account/Upgrading_and_Downgrading":{"id":"Billing_and_Account/Upgrading_and_Downgrading","title":"Upgrading and Downgrading","description":"BandMath offers different subscription tiers to fit the needs of your tour. Whether you just need the core financial ledger, or you want to unlock advanced features like the Merch Analyzer, managing your subscription is easy.","sidebar":"tutorialSidebar"},"Features/advanced-tour-accounting/the-venue-split-calculator":{"id":"Features/advanced-tour-accounting/the-venue-split-calculator","title":"The Venue Split Calculator","description":"Nightly merch settlements are notoriously difficult. BandMath\'s venue split logic automatically calculates the venue\'s cut of gross (or net) sales, subtracts it from the night\'s revenue, and accurately splits the remaining profit among the band members.","sidebar":"tutorialSidebar"},"Features/advanced-tour-accounting/vat-bank-integration":{"id":"Features/advanced-tour-accounting/vat-bank-integration","title":"VAT Bank Integration","description":"Bands can designate a \\"VAT Bank\\" member. The app automatically calculates and siphons the appropriate tax percentage out of the profit pool and safely parks it in the VAT Bank for government remittance, preventing bands from accidentally spending tax money.","sidebar":"tutorialSidebar"},"Features/core-financial-ledger/add-modify-and-delete-transactions":{"id":"Features/core-financial-ledger/add-modify-and-delete-transactions","title":"Add, Modify, and Delete Transactions","description":"Easily record income (anything from tips to payouts), expenses (like gas, hotels, or gear), and money transfers between members. Full editing capabilities ensure the ledger is always accurate.","sidebar":"tutorialSidebar"},"Features/core-financial-ledger/advanced-profit-splitting-the-penny-catcher":{"id":"Features/core-financial-ledger/advanced-profit-splitting-the-penny-catcher","title":"Advanced Profit Splitting (\\"The Penny Catcher\\")","description":"The backend automatically splits income and expenses equally among active members and it dynamically handles rounding errors (e.g., splitting $10.00 three ways) by seamlessly assigning leftover pennies to members in a rotating fashion, guaranteeing perfectly balanced books down to the cent.","sidebar":"tutorialSidebar"},"Features/core-financial-ledger/member-balances-settlements":{"id":"Features/core-financial-ledger/member-balances-settlements","title":"Member Balances & Settlements","description":"The app continually calculates pairwise debts (who owes who exactly what) so that bands can settle up instantly without any manual math.","sidebar":"tutorialSidebar"},"Features/core-financial-ledger/smart-receipt-capture":{"id":"Features/core-financial-ledger/smart-receipt-capture","title":"Smart Receipt Capture","description":"Upload and attach receipt images directly to any transaction, ensuring you always have a digital paper trail.","sidebar":"tutorialSidebar"},"Features/custodial-accounting/automated-debt-settlement":{"id":"Features/custodial-accounting/automated-debt-settlement","title":"Automated Debt Settlement","description":"The app works quietly in the background to solve the complex Debt Settlement problem, continually finding the absolute simplest way for everyone to settle up with the minimum number of money transfers.","sidebar":"tutorialSidebar"},"Features/custodial-accounting/shared-expenses-credits":{"id":"Features/custodial-accounting/shared-expenses-credits","title":"Shared Expenses & Credits","description":"Anyone can pay for anything and automatically debit any combination of the other members. Similarly, anyone can take a payment (like a venue payout) and then credit the other members.","sidebar":"tutorialSidebar"},"Features/export-portability/email-contact-list-export":{"id":"Features/export-portability/email-contact-list-export","title":"Email Contact List Export","description":"A dedicated button instantly downloads a deduplicated, clean CSV of all fan emails collected during the POS checkout. Bands can seamlessly upload this directly into Mailchimp, Klaviyo, or any other marketing tool.","sidebar":"tutorialSidebar"},"Features/export-portability/ledger-export-to-csv":{"id":"Features/export-portability/ledger-export-to-csv","title":"Ledger Export to CSV","description":"A one-click button downloads the entire financial history into a perfectly formatted, spreadsheet-ready CSV. It includes every detail (Descriptions, Tips, Individual Splits, Payment Methods, and Receipt URLs) so accountants can do their jobs effortlessly.","sidebar":"tutorialSidebar"},"Features/merch-inventory-management/historical-cost-tracking":{"id":"Features/merch-inventory-management/historical-cost-tracking","title":"Historical Cost Tracking","description":"BandMath locks in the \\"Cost Goods Sold\\" (COGS) at the time of purchase. If a band buys a batch of shirts for $5 each, and a second batch for $7 each, the app calculates profit using the exact cost of the specific item sold.","sidebar":"tutorialSidebar"},"Features/merch-inventory-management/product-size-management":{"id":"Features/merch-inventory-management/product-size-management","title":"Product & Size Management","description":"Create custom merch items (e.g., \\"Tour Tee\\", \\"Vinyl\\") and manage infinite size variations (S, M, L, XL, etc.).","sidebar":"tutorialSidebar"},"Features/merch-inventory-management/real-time-stock-depletion":{"id":"Features/merch-inventory-management/real-time-stock-depletion","title":"Real-time Stock Depletion","description":"Every time a cart is checked out in the POS, the inventory count for those specific items and sizes is instantly and automatically deducted.","sidebar":"tutorialSidebar"},"Features/the-merch-analyzer/profit-roi-tracking":{"id":"Features/the-merch-analyzer/profit-roi-tracking","title":"Profit & ROI Tracking","description":"View high-level metrics like Gross Revenue, Total Profit, Average Order Value, and Total Items Sold.","sidebar":"tutorialSidebar"},"Features/the-merch-analyzer/restock-warnings":{"id":"Features/the-merch-analyzer/restock-warnings","title":"Restock Warnings","description":"The backend flags items that are running dangerously low on stock or have completely sold out, allowing bands to re-order before losing out on potential revenue.","sidebar":"tutorialSidebar"},"Features/the-merch-analyzer/trophy-awards-top-performers":{"id":"Features/the-merch-analyzer/trophy-awards-top-performers","title":"\\"Trophy\\" Awards (Top Performers)","description":"The app automatically analyzes sales velocity and awards \\"Trophies\\" to the highest-grossing items (e.g., \\"Peony T-shirt - M is your top earner!\\").","sidebar":"tutorialSidebar"},"Features/the-point-of-sale-pos-system/cash-card-tracking":{"id":"Features/the-point-of-sale-pos-system/cash-card-tracking","title":"Cash & Card Tracking","description":"Seamlessly toggle between Cash and Card checkouts to keep an accurate physical cash box count while tracking digital revenue.","sidebar":"tutorialSidebar"},"Features/the-point-of-sale-pos-system/customer-email-capture":{"id":"Features/the-point-of-sale-pos-system/customer-email-capture","title":"Customer Email Capture","description":"Fan emails can be optionally captured during checkout for digital receipts or mailing list signups.","sidebar":"tutorialSidebar"},"Features/the-point-of-sale-pos-system/discounts-tips":{"id":"Features/the-point-of-sale-pos-system/discounts-tips","title":"Discounts & Tips","description":"Apply custom discounts to total orders or accept tips from generous fans. The backend automatically distributes tip revenue directly into the band\'s profit pool.","sidebar":"tutorialSidebar"},"Features/the-point-of-sale-pos-system/dynamic-cart-system":{"id":"Features/the-point-of-sale-pos-system/dynamic-cart-system","title":"Dynamic Cart System","description":"Easily add multiple products and sizes to a cart.","sidebar":"tutorialSidebar"},"Getting_Started/Creating_a_Band":{"id":"Getting_Started/Creating_a_Band","title":"Creating a Band","description":"Welcome to BandMath! Setting up your band is the first step toward gaining total financial clarity for your tours and merchandise.","sidebar":"tutorialSidebar"},"Getting_Started/Inviting_the_Band":{"id":"Getting_Started/Inviting_the_Band","title":"Inviting the Band","description":"BandMath is built for collaboration. To get the most out of the platform, you should invite your bandmates, tour managers, and merch sellers to join your band\'s workspace.","sidebar":"tutorialSidebar"},"Getting_Started/The_First_Tour":{"id":"Getting_Started/The_First_Tour","title":"The First Tour: A Quick Walkthrough","description":"Ready to hit the road? Here is a quick 5-minute walkthrough of the core BandMath loop to get you started on your first tour.","sidebar":"tutorialSidebar"},"Glossary/Glossary_of_Terms":{"id":"Glossary/Glossary_of_Terms","title":"Glossary of Terms","description":"BandMath uses some specific terminology to handle the complexities of tour accounting. If you\'re ever confused by a term in the app, you can reference this glossary.","sidebar":"tutorialSidebar"},"Marketing":{"id":"Marketing","title":"BandMath: Comprehensive Feature Documentation","description":"Last Updated: 2026-06-27","sidebar":"tutorialSidebar"},"Settings_and_Preferences/Localization":{"id":"Settings_and_Preferences/Localization","title":"Localization and Currency","description":"Because BandMath is used by touring bands around the world, you can easily customize the app to fit your region.","sidebar":"tutorialSidebar"},"Settings_and_Preferences/Notifications":{"id":"Settings_and_Preferences/Notifications","title":"Notifications","description":"BandMath keeps you informed about important financial events in your band\'s workspace.","sidebar":"tutorialSidebar"},"Team_Management/Admins_vs_Members":{"id":"Team_Management/Admins_vs_Members","title":"Admins vs. Members","description":"BandMath uses a simple but strict role-based permission system to ensure your financial data remains secure and organized. There are two primary roles in any band workspace: Admins and Members.","sidebar":"tutorialSidebar"},"Team_Management/Claiming_a_Profile":{"id":"Team_Management/Claiming_a_Profile","title":"Claiming a Profile","description":"If you\'ve been operating as a Shadow Profile and you finally decide to download the BandMath app, you can easily \\"claim\\" your profile to view your balances and log your own transactions.","sidebar":"tutorialSidebar"},"Team_Management/Shadow_Profiles":{"id":"Team_Management/Shadow_Profiles","title":"Shadow Profiles","description":"BandMath\'s architecture is designed around a unique concept called Shadow Profiles. This feature exists because we understand the reality of touring bands: not everyone wants to download a finance app.","sidebar":"tutorialSidebar"},"Troubleshooting/At_Cost_Member_Purchase":{"id":"Troubleshooting/At_Cost_Member_Purchase","title":"The \\"At-Cost\\" Member Purchase","description":"The Scenario:","sidebar":"tutorialSidebar"},"Troubleshooting/Incorrect_Merch_Transaction":{"id":"Troubleshooting/Incorrect_Merch_Transaction","title":"The Incorrect Merch Transaction","description":"The Scenario:","sidebar":"tutorialSidebar"},"Troubleshooting/Retroactive_VAT":{"id":"Troubleshooting/Retroactive_VAT","title":"The Retroactive VAT Correction","description":"The Scenario:","sidebar":"tutorialSidebar"}}}}')}}]);